    34→// resourceExpirationEvaluator holds info for deciding if a particular rest.Storage needs to excluded from the API
    35→type resourceExpirationEvaluator struct {
    36→	currentVersion *apimachineryversion.Version
    37→	isAlpha        bool
    38→	// This is usually set for testing for which tests need to be removed.  This prevent insta-failing CI.
    39→	// Set KUBE_APISERVER_STRICT_REMOVED_API_HANDLING_IN_ALPHA to see what will be removed when we tag beta
    40→	strictRemovedHandlingInAlpha bool
    41→	// This is usually set by a cluster-admin looking for a short-term escape hatch after something bad happened.
    42→	// This should be made a flag before merge
    43→	// Set KUBE_APISERVER_SERVE_REMOVED_APIS_FOR_ONE_RELEASE to prevent removing APIs for one more release.
    44→	serveRemovedAPIsOneMoreRelease bool
    45→}
    46→
    47→// ResourceExpirationEvaluator indicates whether or not a resource should be served.
    48→type ResourceExpirationEvaluator interface {
    49→	// RemoveDeletedKinds inspects the storage map and modifies it in place by removing storage for kinds that have been deleted.
    50→	// versionedResourcesStorageMap mirrors the field on APIGroupInfo, it's a map from version to resource to the storage.
    51→	RemoveDeletedKinds(groupName string, versioner runtime.ObjectVersioner, versionedResourcesStorageMap map[string]map[string]rest.Storage)
    52→	// ShouldServeForVersion returns true if a particular version cut off is after the current version
    53→	ShouldServeForVersion(majorRemoved, minorRemoved int) bool
    54→}
